const PROCESSING_FEE_G = 5;
const FIRST_INSURANCE_SURCHARGE_DIVISOR = 10; // 10% surcharge expressed as a divisor (avoids 0.1 float drift)
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PRICE_G = 60;

const COMPONENT_TYPES = ["rune", "moonstone"];

const priceForComponentGroup = (count: number, unitPrice: number): number =>
  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE_G : count * unitPrice;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);

const quotePremium = (items: Item[]): number => {
  const componentBase = COMPONENT_TYPES.reduce((sum, type) => {
    const count = items.filter((i) => i.type === type).length;
    return sum + priceForComponentGroup(count, BASE_PREMIUMS[type]);
  }, 0);
  const otherItemsBase = items
    .filter((i) => !isComponent(i))
    .reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
  const policyBase = otherItemsBase + componentBase;
  const withFirstInsuranceSurcharge = policyBase + policyBase / FIRST_INSURANCE_SURCHARGE_DIVISOR;
  return Math.ceil(withFirstInsuranceSurcharge + PROCESSING_FEE_G);
};
